import { Link } from "react-router-dom";
import "../../styles/auth.css";

export default function ForgotPasswordPage() {
  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-left">
          <h2 className="brand-title">SecureRide</h2>
          <p className="brand-text">Reset your password securely.</p>
        </div>

        <div className="auth-right">
          <h2>Forgot Password</h2>
          <form className="auth-form">
            <label>Email Address</label>
            <input type="email" placeholder="you@example.com" />
            <button className="primary-btn" type="submit">Send Reset Link</button>
            <p className="switch-text">Back to <Link to="/login" className="link">Login</Link></p>
          </form>
        </div>
      </div>
    </div>
  );
}
